SELECT g.name, g.rating
FROM games g
WHERE g.rating > (
  SELECT AVG(rating) FROM games
);

SELECT AVG(g.rating) AS average_game_rating, COUNT(DISTINCT r.user_id) AS number_of_reviewers
FROM games g
JOIN reviews r ON g.game_id = r.game_id;

SELECT STRFTIME('%Y-%m', start_time) AS play_month, COUNT(*) AS total_gameplays
FROM gameplays
GROUP BY play_month;
